with open(path, 'r', encoding='utf-8') as f:
    rows = json.load(f)
# ensure unique by id; compute max copies per id from description
pat = re.compile(r'(\d+)\s+times')
by_id = {}
for r in rows:
    rid = r.get('id')
    desc = r.get('repo_data_description') or ''
    m = pat.search(desc)
    copies = int(m.group(1)) if m else None
    if rid not in by_id or (copies is not None and (by_id[rid]['copies'] is None or copies > by_id[rid]['copies'])):
        by_id[rid] = {'id': rid, 'sample_repo_name': r.get('sample_repo_name'), 'sample_path': r.get('sample_path'), 'copies': copies}
# find max copies
